const searches = [
  { q: 'Customer Success Manager', l: 'Delhi, India', platform: 'indeed_india' },
  { q: 'Client Operations', l: 'Noida', platform: 'indeed_india' },
  { q: 'Project Coordinator', l: 'Delhi NCR', platform: 'indeed_india' },
  { q: 'Business Development Manager consulting', l: 'Delhi', platform: 'indeed_india' },
  { q: 'Customer Success Manager', l: 'Netherlands', platform: 'indeed_eu' },
  { q: 'Operations Manager', l: 'Germany', platform: 'indeed_eu' },
  { q: 'Customer Success remote', l: 'Europe', platform: 'indeed_eu' }
];

return searches.map(s => ({
  json: {
    url: `https://in.indeed.com/jobs?q=${encodeURIComponent(s.q)}&l=${encodeURIComponent(s.l)}&fromage=1&sort=date&limit=20`,
    source_platform: s.platform
  }
}));

const html = typeof $input.first().json === 'string' ? $input.first().json : ($input.first().json.data || '');
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

const jobs = [];

// Extract job IDs from Indeed HTML
const jkMatches = html.match(/data-jk="([a-zA-Z0-9]+)"/g) || [];
const titleMatches = html.match(/class="jobTitle[^"]*"[^>]*><[^>]+>([^<]+)<\/span>/g) || [];
const companyMatches = html.match(/data-testid="company-name"[^>]*>([^<]+)</g) || [];
const locationMatches = html.match(/data-testid="text-location"[^>]*>([^<]+)</g) || [];

const seenIds = new Set();
for (let i = 0; i < jkMatches.length; i++) {
  const idMatch = jkMatches[i].match(/"([a-zA-Z0-9]+)"/);
  if (!idMatch) continue;
  const jk = idMatch[1];
  if (seenIds.has(jk)) continue;
  seenIds.add(jk);

  const title = titleMatches[i] ? titleMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const company = companyMatches[i] ? companyMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const location = locationMatches[i] ? locationMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';

  jobs.push({
    job_id: jk,
    job_title: title,
    company: company,
    location: location,
    job_url: `https://in.indeed.com/viewjob?jk=${jk}`,
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

const seen = $getWorkflowStaticData('global');
if (!seen.indeedSeenIds) seen.indeedSeenIds = [];

const item = $input.first().json;
if (seen.indeedSeenIds.includes(item.job_id)) return [];

seen.indeedSeenIds.push(item.job_id);
if (seen.indeedSeenIds.length > 2000) seen.indeedSeenIds = seen.indeedSeenIds.slice(-1000);

return [{ json: item }];

const html = typeof $input.first().json === 'string' ? $input.first().json : ($input.first().json.data || '');
const prev = $('Deduplicate').first().json;

const descMatch = html.match(/id="jobDescriptionText"[^>]*>([\s\S]*?)<\/div>/);
let description = '';
if (descMatch) {
  description = descMatch[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}
if (!description || description.length < 50) {
  description = `${prev.job_title} at ${prev.company}, ${prev.location}. See: ${prev.job_url}`;
}

return [{ json: { ...prev, description: description.substring(0, 3000) } }];
